mapper.select:
SELECT o.order_no, p.product_name, o.order_status, o.order_deadline, mr.employee_id FROM orders o JOIN product p ON o.product_id = p.product_id LEFT JOIN matching_record mr ON o.order_id = mr.order_id AND mr.matching_status = 'CONFIRM'
AND o.order_status = #{status}
AND (o.order_no LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY o.order_deadline ASC
LIMIT #{size} OFFSET #{page}
